hooks.onDraw:
var s = world.state;
var W = world.W, H = world.H;
var T = world.t;
var standBot = 150, fieldTop = 196, nearLine = 516, goalLine = 880;
// --- tribuna: respaldo + gradas ---
ctx.fillStyle = '#39415a';
ctx.fillRect(0, 0, W, standBot);
ctx.fillStyle = '#2c3247';
ctx.fillRect(0, 0, W, 7);
ctx.fillStyle = 'rgba(0,0,0,0.12)';
ctx.fillRect(0, 50, W, 3); ctx.fillRect(0, 98, W, 3);
ctx.fillStyle = '#454d68';
ctx.fillRect(0, standBot - 6, W, 6);
// --- publico: BLOBS propios (cuerpo + ojos, como los jugadores) que saltan ---
var hype = s.hype || 0;
for (var ry = 0; ry < 3; ry++) {
  for (var rx = 0; rx < 27; rx++) {
    var ph = rx * 0.5 + ry * 1.9;
    var jump = Math.abs(Math.sin(T * 2.8 + ph)) * (4 + hype * 20);
    var cx = 22 + rx * 36;
    var cy = 48 + ry * 42 - jump;
    var tc = (rx * 2 + ry * 5) % 6;
    var col = (tc < 3) ? '#5b8def' : (tc < 5 ? '#c44a3e' : '#e6c34a');
    world.draw.rrect(cx - 11, cy - 13, 22, 26, 9);
    ctx.fillStyle = col; ctx.fill();
    ctx.fillStyle = 'rgba(0,0,0,0.12)';
    world.draw.rrect(cx - 11, cy + 4, 22, 9, 6); ctx.fill();
    ctx.fillStyle = '#fbfaf6';
    ctx.beginPath(); ctx.arc(cx - 4.5, cy - 4, 3, 0, 6.283); ctx.fill();
    ctx.beginPath(); ctx.arc(cx + 4.5, cy - 4, 3, 0, 6.283); ctx.fill();
    ctx.fillStyle = '#22262f';
    ctx.beginPath(); ctx.arc(cx - 4.5, cy - 3.4, 1.5, 0, 6.283); ctx.fill();
    ctx.beginPath(); ctx.arc(cx + 4.5, cy - 3.4, 1.5, 0, 6.283); ctx.fill();
  }
}
// --- banda (fuera del campo, donde corre el juez) ---
ctx.fillStyle = 'rgba(0,0,0,0.06)';
ctx.fillRect(0, standBot, W, fieldTop - standBot);
// --- franjas de corte del cesped ---
ctx.save();
for (var i = 0; i < 12; i++) {
  ctx.fillStyle = (i % 2 === 0) ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.055)';
  ctx.fillRect(i * 92 - 16, fieldTop, 92, H - fieldTop);
}
ctx.restore();
// --- lineas del campo (vista cenital), centradas en el eje del campo ---
var midY = (fieldTop + nearLine) / 2;
ctx.strokeStyle = 'rgba(251,250,246,0.5)';
ctx.lineWidth = 2;
ctx.beginPath(); ctx.moveTo(0, fieldTop); ctx.lineTo(W, fieldTop); ctx.stroke();
ctx.beginPath(); ctx.moveTo(0, nearLine); ctx.lineTo(W, nearLine); ctx.stroke();
ctx.beginPath(); ctx.moveTo(goalLine, fieldTop); ctx.lineTo(goalLine, nearLine); ctx.stroke();
ctx.strokeRect(636, midY - 103, 244, 206);
ctx.strokeRect(800, midY - 60, 80, 120);
ctx.beginPath(); ctx.moveTo(60, fieldTop); ctx.lineTo(60, nearLine); ctx.stroke();
ctx.fillStyle = 'rgba(251,250,246,0.6)';
ctx.beginPath(); ctx.arc(742, midY, 2.4, 0, 6.283); ctx.fill();
// --- arco minimo: huella plana al nivel de las lineas de cancha (sin red, sin volumen) ---
var glx = goalLine, gpt = midY - 56, gpb = midY + 56, gbk = glx + 40;
ctx.strokeStyle = 'rgba(251,250,246,0.5)';
ctx.lineWidth = 2;
ctx.beginPath();
ctx.moveTo(glx, gpt); ctx.lineTo(gbk, gpt); ctx.lineTo(gbk, gpb); ctx.lineTo(glx, gpb);
ctx.stroke();
ctx.fillStyle = '#FBFAF6';
ctx.beginPath(); ctx.arc(glx, gpt, 3.5, 0, 6.283); ctx.fill();
ctx.beginPath(); ctx.arc(glx, gpb, 3.5, 0, 6.283); ctx.fill();
// --- linea de fuera de juego + zona ---
if ((s.lineOn || 0) > 0.01) {
  var lx = s.lineX || 600;
  var t2 = fieldTop + 4, b2 = nearLine - 4;
  ctx.save();
  ctx.globalAlpha = 0.15 * s.lineOn;
  ctx.fillStyle = '#c44a3e';
  ctx.fillRect(lx, t2, goalLine - lx, b2 - t2);
  ctx.restore();
  ctx.save();
  ctx.globalAlpha = Math.min(1, s.lineOn);
  ctx.strokeStyle = '#F4AC1D';
  ctx.lineWidth = 3;
  ctx.beginPath(); ctx.moveTo(lx, t2 - 6); ctx.lineTo(lx, b2); ctx.stroke();
  ctx.fillStyle = '#F4AC1D';
  ctx.beginPath(); ctx.moveTo(lx - 6, t2 - 6); ctx.lineTo(lx + 6, t2 - 6); ctx.lineTo(lx, t2 + 5); ctx.closePath(); ctx.fill();
  ctx.restore();
}
// --- learners (la escena define onDraw: los dibuja ella, con y-sort) ---
var lsd = world.entities.filter(function (e) { return e.type === 'learner'; });
lsd.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (var k = 0; k < lsd.length; k++) world.draw.learner(lsd[k]);
// --- regla 'un blob': cuanto pasa la linea (durante el congelado) ---
if ((s.lineOn || 0) > 0.6) {
  var d = world.byId('delantero');
  if (d) {
    var lx2 = s.lineX || 600;
    var my = 448;
    ctx.save();
    ctx.globalAlpha = Math.min(1, (s.lineOn - 0.6) * 2.5);
    ctx.strokeStyle = '#F4AC1D';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(lx2, my - 6); ctx.lineTo(lx2, my + 6);
    ctx.moveTo(d.x, my - 6); ctx.lineTo(d.x, my + 6);
    ctx.moveTo(lx2, my); ctx.lineTo(d.x, my);
    ctx.stroke();
    var midx = (lx2 + d.x) / 2;
    world.draw.rrect(midx - 42, my - 31, 84, 18, 5);
    ctx.fillStyle = '#1F2547'; ctx.fill();
    ctx.fillStyle = '#F4AC1D';
    ctx.font = '600 11px "Plus Jakarta Sans", ui-sans-serif';
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText('1 Pirulete', midx, my - 22);
    ctx.restore();
  }
}
// --- balon ---
if (s.ballX != null) {
  var bx2 = s.ballX, by2 = s.ballY;
  ctx.save();
  ctx.globalAlpha = 0.22;
  ctx.fillStyle = '#16310f';
  ctx.beginPath(); ctx.ellipse(bx2, by2 + 8, 8, 3, 0, 0, 6.283); ctx.fill();
  ctx.restore();
  ctx.fillStyle = '#fbfaf6';
  ctx.beginPath(); ctx.arc(bx2, by2, 7, 0, 6.283); ctx.fill();
  ctx.fillStyle = '#23303f';
  ctx.beginPath(); ctx.arc(bx2, by2, 2.4, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(bx2 - 4, by2 - 3, 1.5, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(bx2 + 4, by2 - 2, 1.5, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(bx2 - 1, by2 + 4, 1.5, 0, 6.283); ctx.fill();
  ctx.fillStyle = 'rgba(255,255,255,0.7)';
  ctx.beginPath(); ctx.arc(bx2 - 2.4, by2 - 2.4, 1.8, 0, 6.283); ctx.fill();
}
// --- juez de linea (en la banda): bandera amarilla que sube ---
var j = world.byId('juez');
if (j) {
  var up = s.flagUp || 0;
  var hx = j.x + 16, hy = j.y - 6;
  var ang = -0.4 + up * 1.7;
  var len = 36;
  var ex = hx + Math.cos(ang) * len, ey = hy - Math.sin(ang) * len;
  ctx.strokeStyle = '#d8dbe4';
  ctx.lineWidth = 2.5;
  ctx.beginPath(); ctx.moveTo(hx, hy); ctx.lineTo(ex, ey); ctx.stroke();
  var perpx = Math.cos(ang + 1.5708), perpy = -Math.sin(ang + 1.5708);
  var bxp = ex - Math.cos(ang) * 22, byp = ey + Math.sin(ang) * 22;
  ctx.fillStyle = '#f4d21f';
  ctx.beginPath();
  ctx.moveTo(ex, ey);
  ctx.lineTo(bxp + perpx * 16, byp + perpy * 16);
  ctx.lineTo(bxp, byp);
  ctx.closePath(); ctx.fill();
  ctx.fillStyle = '#c44a3e';
  ctx.beginPath();
  ctx.moveTo(bxp, byp);
  ctx.lineTo(bxp + perpx * 16, byp + perpy * 16);
  ctx.lineTo((bxp + ex) / 2 + perpx * 8, (byp + ey) / 2 + perpy * 8);
  ctx.closePath(); ctx.fill();
}
